import hashlib

def file_hash(file_path, hash_function=hashlib.sha256):
    """Compute the hash of a file."""
    hasher = hash_function()
    with open(file_path, 'rb') as f:
        for chunk in iter(lambda: f.read(4096), b""):
            hasher.update(chunk)
    return hasher.hexdigest()

